import "./App.css";
import Navbar from "./component/Navbar";
import TextFrom from "./component/TextForm";
import React, { useState } from "react";
import Aleart from "./component/Aleart";
function App() {
  const [mode, setMode] = useState('light');
  const [aleart, setAleart] = useState('hey how are you');
  let toggleMode = () => {
    if (mode === 'light') {
      setMode('dark');
      document.body.style.backgroundColor='rgb(2 28 70)'
    } else {
      setMode('light');
      document.body.style.backgroundColor='white'
    }
  };
  let showAleart= (massage,type)=>{
    setAleart({
msg:massage,
type:type
    })
  } 

  return (
    <>
      <Navbar
        Title="Text Utiles"
        about="About Us"
        mode={mode}
        toggleMode={toggleMode}
      />
      <Aleart aleart={aleart}/>
      <div className="container">
        <TextFrom  mode={mode} heading="Enter Your Text To Analyse Below" />
      </div>
    </>
  );
}

export default App;
